class Solution:
    def minTime(self, s, order, k):
        n = len(s)
        for t in range(n):
            star = [False] * n
            for i in range(t + 1):
                star[order[i]] = True
            valid = 0
            for i in range(n):
                has = False
                for j in range(i, n):
                    if star[j]:
                        has = True
                    if has:
                        valid += 1
            if valid >= k:
                return t
        return -1

