class Solution:
    def minTime(self, s, order, k):
        n = len(s)
        total = n * (n + 1) // 2
        def valid(t):
            star = [False] * n
            for i in range(t + 1):
                star[order[i]] = True
            gap = 0
            blocked = 0
            for i in range(n):
                if star[i]:
                    blocked += gap * (gap + 1) // 2
                    gap = 0
                else:
                    gap += 1
            blocked += gap * (gap + 1) // 2
            return total - blocked
        if valid(n - 1) < k:
            return -1
        lo, hi, ans = 0, n - 1, n - 1
        while lo <= hi:
            mid = (lo + hi) // 2
            if valid(mid) >= k:
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        return ans

