var minTime = function(s, order, k) {
    const n = s.length;
    const total = n * (n + 1) / 2;
    const valid = (t) => {
        const star = new Array(n).fill(false);
        for (let i = 0; i <= t; i++) star[order[i]] = true;
        let gap = 0, blocked = 0;
        for (let i = 0; i < n; i++) {
            if (star[i]) { blocked += gap * (gap + 1) / 2; gap = 0; }
            else gap++;
        }
        blocked += gap * (gap + 1) / 2;
        return total - blocked;
    };
    if (valid(n - 1) < k) return -1;
    let lo = 0, hi = n - 1, ans = n - 1;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (valid(mid) >= k) { ans = mid; hi = mid - 1; }
        else lo = mid + 1;
    }
    return ans;
};
